"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { motion } from "motion/react";
import { Gamepad2, Plus, LogIn, Trophy } from "lucide-react";
import { getLeaderboard } from "@/lib/actions";
import { getSocket } from "@/lib/socket";

export default function Home() {
  const [username, setUsername] = useState("");
  const [joinRoomId, setJoinRoomId] = useState("");
  const [showJoinInput, setShowJoinInput] = useState(false);
  const [isCreating, setIsCreating] = useState(false);
  const [leaderboard, setLeaderboard] = useState<{ username: string, wins: number }[]>([]);
  const router = useRouter();

  useEffect(() => {
    getLeaderboard().then(setLeaderboard);
  }, []);

  const handleCreateRoom = () => {
    if (!username) return alert("Please enter a username");
    if (isCreating) return;
    setIsCreating(true);

    sessionStorage.setItem("wordquest_username", username);

    const socket = getSocket();
    if (!socket.connected) {
      socket.connect();
    }

    socket.emit("createRoom", { username });

    socket.once("roomCreated", (data) => {
      console.log("Received room:", data.roomId);
      router.push(`/room/${data.roomId}`);
    });

    // ✅ safety fallback
    setTimeout(() => {
      setIsCreating(false);
    }, 5000);
  };

  const handleJoinRoom = () => {
    if (!username) return alert("Please enter a username");
    if (!showJoinInput) {
      setShowJoinInput(true);
      return;
    }
    if (!joinRoomId) return alert("Please enter a Room ID");
    sessionStorage.setItem("wordquest_username", username);
    router.push(`/room/${joinRoomId.toUpperCase()}`);
  };

  return (
    <main className="relative flex min-h-screen items-center justify-center overflow-hidden bg-[#0a0c14] p-4 text-white">
      {/* Dynamic Background Elements */}
      <div className="absolute top-0 -left-48 h-96 w-96 rounded-full bg-blue-600/20 blur-[120px]" />
      <div className="absolute bottom-0 -right-48 h-96 w-96 rounded-full bg-purple-600/20 blur-[120px]" />

      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6, ease: "easeOut" }}
        className="glass-card relative z-10 w-full max-w-[440px] border border-white/10 bg-white/[0.03] p-8 md:p-12"
      >
        <div className="mb-10 text-center">
          <motion.div
            initial={{ scale: 0.8 }}
            animate={{ scale: 1 }}
            className="mx-auto mb-6 flex h-20 w-20 items-center justify-center rounded-2xl bg-gradient-to-br from-blue-500 to-blue-700 shadow-lg shadow-blue-500/25"
          >
            <Gamepad2 size={40} className="text-white" />
          </motion.div>
          <h1 className="text-4xl font-black tracking-tight text-white md:text-5xl">
            WORDQUEST
          </h1>
          <p className="mt-3 text-lg font-medium text-slate-400">
            Real-time Multiplayer Guessing
          </p>
        </div>

        <div className="space-y-6">
          <div className="space-y-2">
            <label className="text-sm font-semibold uppercase tracking-wider text-slate-500">
              Identity
            </label>
            <Input
              placeholder="Your Username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              className="h-14 border-white/10 bg-white/5 text-lg placeholder:text-slate-600 focus:border-blue-500/50"
            />
          </div>

          <motion.div animate={{ height: "auto" }} className="space-y-4 pt-4">
            {showJoinInput && (
              <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                className="space-y-2"
              >
                <label className="text-sm font-semibold uppercase tracking-wider text-slate-500">
                  Room ID
                </label>
                <Input
                  placeholder="E.g. XJ9V2L"
                  value={joinRoomId}
                  onChange={(e) => setJoinRoomId(e.target.value.toUpperCase())}
                  className="h-14 border-white/10 bg-white/5 text-lg placeholder:text-slate-600 focus:border-blue-500/50"
                  autoFocus
                />
              </motion.div>
            )}

            <div className="grid gap-4">
              <Button
                onClick={handleCreateRoom}
                className="group h-14 w-full gap-2 rounded-xl bg-gradient-to-r from-blue-600 to-blue-500 text-lg font-bold transition-all hover:translate-y-[-2px] hover:shadow-xl hover:shadow-blue-500/20 active:translate-y-0"
              >
                <Plus size={20} className="transition-transform group-hover:rotate-90" />
                {isCreating ? "Creating..." : "Create Room"}
              </Button>

              <Button
                onClick={handleJoinRoom}
                variant="outline"
                className="h-14 w-full gap-2 rounded-xl border-white/10 bg-white/5 text-lg font-bold backdrop-blur-sm transition-all hover:bg-white/10 hover:text-white"
              >
                <LogIn size={20} />
                {showJoinInput ? "Join Match" : "Join Existing Room"}
              </Button>
            </div>
          </motion.div>
        </div>

        <div className="mt-12 flex items-center justify-end text-xs font-bold uppercase tracking-widest text-slate-600">
          <span>Online Competitive</span>
        </div>

        {/* Global Leaderboard Section */}
        {leaderboard.length > 0 && (
          <div className="mt-8 border-t border-white/5 pt-8">
            <h3 className="mb-4 flex items-center gap-2 text-xs font-black uppercase tracking-[0.2em] text-slate-500">
              <Trophy size={14} className="text-yellow-500" /> Champions Hall
            </h3>
            <div className="space-y-3">
              {leaderboard.map((user, i) => (
                <div key={user.username} className="flex items-center justify-between text-sm">
                  <div className="flex items-center gap-3">
                    <span className="w-4 font-mono text-[10px] text-slate-600">{i + 1}</span>
                    <span className="font-bold text-slate-300">{user.username}</span>
                  </div>
                  <span className="font-mono text-blue-400">{user.wins} <span className="text-[10px] text-slate-600 uppercase">Wins</span></span>
                </div>
              ))}
            </div>
          </div>
        )}
      </motion.div>
    </main>
  );
}
